17	// RBTDRP — pristine-lifecycle fixture for theurge release qualification
18	//
19	// Case 1 (marshal-zero-attestation) is the entry gate for `rbw-tP`. It asserts
20	// that the working tree was just zeroed by `rbw-MZ` (rblm_zero) — five
21	// violation classes are checked and ALL surfaced in one aggregated diagnostic.
22	// Failure short-circuits subsequent cases via the per-fixture fail_fast switch.
23	
24	use std::path::{Path, PathBuf};
25	use std::process::Command;
26	
27	use crate::case;
28	use crate::rbtdre_engine::{rbtdre_Section, rbtdre_Verdict};
29	
30	/// RBRR field names referenced by the pristine-lifecycle fixture. Field
31	/// identifiers extracted as consts so the blank-field array and the
32	/// throwaway-prefix install helper share a single definition site.
33	const RBTDRP_FIELD_RBRR_CLOUD_PREFIX: &str = "RBRR_CLOUD_PREFIX";
34	const RBTDRP_FIELD_RBRR_RUNTIME_PREFIX: &str = "RBRR_RUNTIME_PREFIX";
35	
36	/// Site-specific RBRR fields that rblm_zero blanks. These five fields define
37	/// the depot-bound site identity; an empty value is the post-marshal-zero
38	/// invariant.
39	const RBTDRP_RBRR_BLANK_FIELDS: &[&str] = &[
40	    "RBRR_DEPOT_PROJECT_ID",
41	    "RBRR_GAR_REPOSITORY",
42	    "RBRR_GCB_POOL_STEM",
43	    RBTDRP_FIELD_RBRR_CLOUD_PREFIX,
44	    RBTDRP_FIELD_RBRR_RUNTIME_PREFIX,
45	];
46	
47	/// Throwaway RBRR prefix values stamped into rbrr.env by
48	/// `rbtdrp_install_throwaway_prefixes`. Pristine-lifecycle cases that need
49	/// non-blank prefixes (depot/governor/retriever/director lifecycle) call the
50	/// helper to install these values; the marker shape distinguishes throwaway
51	/// from operator-chosen canonical values.
52	#[allow(dead_code)]
53	pub(crate) const RBTDRP_THROWAWAY_CLOUD_PREFIX: &str = "prlc-";
54	#[allow(dead_code)]
55	pub(crate) const RBTDRP_THROWAWAY_RUNTIME_PREFIX: &str = "prlr-";
56	
57	/// Roles whose RBRA credential files rblm_zero deletes.
58	const RBTDRP_RBRA_ROLES: &[&str] = &["governor", "director", "retriever", "assay"];
59	
60	/// Nameplate hallmark fields rblm_zero blanks.
61	const RBTDRP_RBRN_BLANK_FIELDS: &[&str] = &["RBRN_SENTRY_HALLMARK", "RBRN_BOTTLE_HALLMARK"];
62	
63	/// File-relative constants matching rbbc_constants.sh / rbcc_Constants.sh.
64	const RBTDRP_DOT_DIR: &str = ".rbk";
65	const RBTDRP_RBRR_FILE: &str = ".rbk/rbrr.env";
66	const RBTDRP_RBRA_FILE: &str = "rbra.env";
67	const RBTDRP_RBRN_FILE: &str = "rbrn.env";
68	const RBTDRP_RBRV_FILE: &str = "rbrv.env";
69	
70	// ── Helpers ──────────────────────────────────────────────────
71	
72	/// Read an env file and return the value for `key`, or None if the key is
73	/// absent. The bash regime files use `KEY=value` lines (unquoted); comment
74	/// and blank lines are skipped. The trailing newline is stripped from value.
75	fn rbtdrp_read_env_value(path: &Path, key: &str) -> Option<String> {
76	    let content = std::fs::read_to_string(path).ok()?;
77	    let prefix = format!("{}=", key);
78	    for line in content.lines() {
79	        let trimmed = line.trim_start();
80	        if trimmed.starts_with('#') {
81	            continue;
82	        }
83	        if let Some(rest) = trimmed.strip_prefix(&prefix) {
84	            return Some(rest.to_string());
85	        }
86	    }
87	    None
88	}
89	
90	/// Resolve a path that may be absolute or relative-to-project-root.
91	fn rbtdrp_resolve(root: &Path, raw: &str) -> PathBuf {
92	    if Path::new(raw).is_absolute() {
93	        PathBuf::from(raw)
94	    } else {
95	        root.join(raw)
96	    }
97	}
98	
99	/// Class A — working tree clean (`git status --porcelain` empty).
100	fn rbtdrp_check_tree_clean(root: &Path, violations: &mut Vec<String>) {
101	    match Command::new("git")
102	        .args(["status", "--porcelain"])
103	        .current_dir(root)
104	        .output()
105	    {
106	        Ok(out) if out.status.success() => {
107	            let stdout = String::from_utf8_lossy(&out.stdout);
108	            let trimmed = stdout.trim();
109	            if !trimmed.is_empty() {
110	                violations.push(format!(
111	                    "working tree not clean — uncommitted changes:\n{}",
112	                    trimmed
113	                ));
114	            }
115	        }
116	        Ok(out) => violations.push(format!(
117	            "git status --porcelain failed (exit {}): {}",
118	            out.status.code().unwrap_or(-1),
119	            String::from_utf8_lossy(&out.stderr).trim()
120	        )),
121	        Err(e) => violations.push(format!("git status invocation failed: {}", e)),
122	    }
123	}
124	
125	/// Class B — five site-specific RBRR fields are blank.
126	fn rbtdrp_check_rbrr_fields(rbrr: &Path, violations: &mut Vec<String>) {
127	    for field in RBTDRP_RBRR_BLANK_FIELDS {
128	        if let Some(value) = rbtdrp_read_env_value(rbrr, field) {
129	            if !value.is_empty() {
130	                violations.push(format!(
131	                    "RBRR field non-blank: {}={} (in {})",
132	                    field,
133	                    value,
134	                    rbrr.display()
135	                ));
136	            }
137	        }
138	    }
139	}
140	
141	/// Class C — no RBRA credential files at the four role paths.
142	fn rbtdrp_check_rbra_files(root: &Path, secrets_dir: &str, violations: &mut Vec<String>) {
143	    if secrets_dir.is_empty() {
144	        violations.push(
145	            "RBRR_SECRETS_DIR is blank — cannot resolve credential paths".to_string(),
146	        );
147	        return;
148	    }
149	    let secrets = rbtdrp_resolve(root, secrets_dir);
150	    for role in RBTDRP_RBRA_ROLES {
151	        let path = secrets.join(role).join(RBTDRP_RBRA_FILE);
152	        if path.exists() {
153	            violations.push(format!("RBRA credential present: {}", path.display()));
154	        }
155	    }
156	}
157	
158	/// Class D — every nameplate's RBRN_SENTRY_HALLMARK and RBRN_BOTTLE_HALLMARK
159	/// is blank.
160	fn rbtdrp_check_nameplate_hallmarks(root: &Path, violations: &mut Vec<String>) {
161	    let dot_dir = root.join(RBTDRP_DOT_DIR);
162	    let entries = match std::fs::read_dir(&dot_dir) {
163	        Ok(e) => e,
164	        Err(e) => {
165	            violations.push(format!("cannot read {}: {}", dot_dir.display(), e));
166	            return;
167	        }
168	    };
169	    for entry in entries.flatten() {
170	        let np_dir = entry.path();
171	        if !np_dir.is_dir() {
172	            continue;
173	        }
174	        let rbrn = np_dir.join(RBTDRP_RBRN_FILE);
175	        if !rbrn.exists() {
176	            continue;
177	        }
178	        for field in RBTDRP_RBRN_BLANK_FIELDS {
179	            if let Some(value) = rbtdrp_read_env_value(&rbrn, field) {
180	                if !value.is_empty() {
181	                    violations.push(format!(
182	                        "nameplate hallmark non-blank: {}={} (in {})",
183	                        field,
184	                        value,
185	                        rbrn.display()
186	                    ));
187	                }
188	            }
189	        }
190	    }
191	}
192	
193	/// Class E — every vessel rbrv.env has RBRV_RELIQUARY blank and every
194	/// RBRV_IMAGE_*_ANCHOR field blank.
195	fn rbtdrp_check_vessel_depot_fields(
196	    root: &Path,
197	    vessel_dir: &str,
198	    violations: &mut Vec<String>,
199	) {
200	    if vessel_dir.is_empty() {
201	        violations.push("RBRR_VESSEL_DIR is blank — cannot scan vessels".to_string());
202	        return;
203	    }
204	    let vroot = rbtdrp_resolve(root, vessel_dir);
205	    let entries = match std::fs::read_dir(&vroot) {
206	        Ok(e) => e,
207	        Err(e) => {
208	            violations.push(format!("cannot read {}: {}", vroot.display(), e));
209	            return;
210	        }
211	    };
212	    for entry in entries.flatten() {
213	        let v_dir = entry.path();
214	        if !v_dir.is_dir() {
215	            continue;
216	        }
217	        let rbrv = v_dir.join(RBTDRP_RBRV_FILE);
218	        if !rbrv.exists() {
219	            continue;
220	        }
221	        rbtdrp_scan_rbrv_file(&rbrv, violations);
222	    }
223	}
224	
225	/// Scan a single rbrv.env for non-blank RBRV_RELIQUARY and RBRV_IMAGE_*_ANCHOR
226	/// fields.
227	fn rbtdrp_scan_rbrv_file(rbrv: &Path, violations: &mut Vec<String>) {
228	    let content = match std::fs::read_to_string(rbrv) {
229	        Ok(c) => c,
230	        Err(e) => {
231	            violations.push(format!("cannot read {}: {}", rbrv.display(), e));
232	            return;
233	        }
234	    };
235	    for line in content.lines() {
236	        let trimmed = line.trim_start();
237	        if trimmed.starts_with('#') {
238	            continue;
239	        }
240	        let (key, value) = match trimmed.split_once('=') {
241	            Some(kv) => kv,
242	            None => continue,
243	        };
244	        let is_reliquary = key == "RBRV_RELIQUARY";
245	        let is_anchor = key.starts_with("RBRV_IMAGE_") && key.ends_with("_ANCHOR");
246	        if (is_reliquary || is_anchor) && !value.is_empty() {
247	            violations.push(format!(
248	                "vessel depot-scoped field non-blank: {}={} (in {})",
249	                key,
250	                value,
251	                rbrv.display()
252	            ));
253	        }
254	    }
255	}
256	
257	// ── Throwaway-prefix install ─────────────────────────────────
258	
259	/// Replace the `RBRR_CLOUD_PREFIX=` and `RBRR_RUNTIME_PREFIX=` lines in
260	/// rbrr.env content with throwaway values, preserving all other lines and
261	/// the trailing-newline shape.
262	#[allow(dead_code)]
263	fn rbtdrp_replace_prefix_lines(content: &str) -> String {
264	    let cloud_assign = format!("{}=", RBTDRP_FIELD_RBRR_CLOUD_PREFIX);
265	    let runtime_assign = format!("{}=", RBTDRP_FIELD_RBRR_RUNTIME_PREFIX);
266	    let mut result: String = content
267	        .lines()
268	        .map(|line| {
269	            if line.starts_with(&cloud_assign) {
270	                format!("{}{}", cloud_assign, RBTDRP_THROWAWAY_CLOUD_PREFIX)
271	            } else if line.starts_with(&runtime_assign) {
272	                format!("{}{}", runtime_assign, RBTDRP_THROWAWAY_RUNTIME_PREFIX)
273	            } else {
274	                line.to_string()
275	            }
276	        })
277	        .collect::<Vec<_>>()
278	        .join("\n");
279	    if content.ends_with('\n') {
280	        result.push('\n');
281	    }
282	    result
283	}
284	
285	/// Idempotently install throwaway RBRR prefixes into `.rbk/rbrr.env`.
286	///
287	/// Pristine-lifecycle cases that need non-blank prefixes (depot/governor/
288	/// retriever/director lifecycle) call this as their first step. The helper
289	/// reads current values; if `RBRR_CLOUD_PREFIX` and `RBRR_RUNTIME_PREFIX`
290	/// already match the throwaway markers, returns `Ok(())` with no side
291	/// effect. Otherwise rewrites both lines in place, then `git add` +
292	/// `git commit` the change. One commit per fixture run regardless of which
293	/// case is the first to call it.
294	///
295	/// HEAD walks off marshal-zero after the commit; recovery is `rbw-MZ`,
296	/// matching the pristine fixture's start-over-from-zero failure mode.
297	#[allow(dead_code)]
298	pub(crate) fn rbtdrp_install_throwaway_prefixes(root: &Path) -> Result<(), String> {
299	    let rbrr = root.join(RBTDRP_RBRR_FILE);
300	    let cloud = rbtdrp_read_env_value(&rbrr, RBTDRP_FIELD_RBRR_CLOUD_PREFIX).unwrap_or_default();
301	    let runtime =
302	        rbtdrp_read_env_value(&rbrr, RBTDRP_FIELD_RBRR_RUNTIME_PREFIX).unwrap_or_default();
303	
304	    if cloud == RBTDRP_THROWAWAY_CLOUD_PREFIX && runtime == RBTDRP_THROWAWAY_RUNTIME_PREFIX {
305	        return Ok(());
306	    }
307	
308	    let content = std::fs::read_to_string(&rbrr)
309	        .map_err(|e| format!("rbtdrp: read {}: {}", rbrr.display(), e))?;
310	    let new_content = rbtdrp_replace_prefix_lines(&content);
311	    std::fs::write(&rbrr, &new_content)
312	        .map_err(|e| format!("rbtdrp: write {}: {}", rbrr.display(), e))?;
313	
314	    let add = Command::new("git")
315	        .args(["add", RBTDRP_RBRR_FILE])
316	        .current_dir(root)
317	        .output()
318	        .map_err(|e| format!("rbtdrp: git add invocation failed: {}", e))?;
319	    if !add.status.success() {
320	        return Err(format!(
321	            "rbtdrp: git add failed (exit {}): {}",
322	            add.status.code().unwrap_or(-1),
323	            String::from_utf8_lossy(&add.stderr).trim()
324	        ));
325	    }
326	
327	    let commit_msg = format!(
328	        "pristine-lifecycle fixture: install throwaway RBRR prefixes ({}/{})",
329	        RBTDRP_THROWAWAY_CLOUD_PREFIX, RBTDRP_THROWAWAY_RUNTIME_PREFIX
330	    );
331	    let commit = Command::new("git")
332	        .args(["commit", "-m", &commit_msg])
333	        .current_dir(root)
334	        .output()
335	        .map_err(|e| format!("rbtdrp: git commit invocation failed: {}", e))?;
336	    if !commit.status.success() {
337	        return Err(format!(
338	            "rbtdrp: git commit failed (exit {}): {}",
339	            commit.status.code().unwrap_or(-1),
340	            String::from_utf8_lossy(&commit.stderr).trim()
341	        ));
342	    }
343	
344	    Ok(())
345	}
346	
347	// ── Case ─────────────────────────────────────────────────────
348	
349	/// Case 1 — marshal-zero attestation. Aggregates all five violation classes
350	/// into a single diagnostic. A passing run is the proof that `rbw-MZ` was
351	/// just executed and committed.
352	fn rbtdrp_marshal_zero_attestation(_dir: &Path) -> rbtdre_Verdict {
353	    let root = match std::env::current_dir() {
354	        Ok(r) => r,
355	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot resolve project root: {}", e)),
356	    };
357	
358	    let rbrr = root.join(RBTDRP_RBRR_FILE);
359	    if !rbrr.exists() {
360	        return rbtdre_Verdict::Fail(format!("RBRR file not found: {}", rbrr.display()));
361	    }
362	
363	    let secrets_dir = rbtdrp_read_env_value(&rbrr, "RBRR_SECRETS_DIR").unwrap_or_default();
364	    let vessel_dir = rbtdrp_read_env_value(&rbrr, "RBRR_VESSEL_DIR").unwrap_or_default();
365	
366	    let mut violations: Vec<String> = Vec::new();
367	
368	    rbtdrp_check_tree_clean(&root, &mut violations);
369	    rbtdrp_check_rbrr_fields(&rbrr, &mut violations);
370	    rbtdrp_check_rbra_files(&root, &secrets_dir, &mut violations);
371	    rbtdrp_check_nameplate_hallmarks(&root, &mut violations);
372	    rbtdrp_check_vessel_depot_fields(&root, &vessel_dir, &mut violations);
373	
374	    if violations.is_empty() {
375	        return rbtdre_Verdict::Pass;
376	    }
377	
378	    let body = violations
379	        .iter()
380	        .map(|v| format!("  - {}", v))
381	        .collect::<Vec<_>>()
382	        .join("\n");
383	    rbtdre_Verdict::Fail(format!(
384	        "marshal-zero attestation failed — {} violation(s):\n{}\n\n\
385	         remedy: tt/rbw-MZ.MarshalZeroes.sh, then commit and rerun.",
386	        violations.len(),
387	        body
388	    ))
389	}
390	
391	// ── Section registry ─────────────────────────────────────────
392	
393	pub static RBTDRP_SECTIONS_PRISTINE_LIFECYCLE: &[rbtdre_Section] = &[rbtdre_Section {
394	    name: "pristine-lifecycle-gate",
395	    cases: &[case!(rbtdrp_marshal_zero_attestation)],
396	}];
