use std::path::{Path, PathBuf};
use std::process::Command;

use crate::rbtdre_engine::rbtdre_Verdict;
use crate::rbtdrm_manifest::RBTDRM_COLOPHON_BARK;

/// Ifrit binary name inside the bottle container.
