16	//
17	// RBTDRE — case execution engine for theurge
18	
19	use std::path::Path;
20	use std::path::PathBuf;
21	
22	// ── Verdict ────────────────────────────────────────────────────
23	
24	/// Verdict from a single test case execution.
25	pub enum rbtdre_Verdict {
26	    Pass,
27	    Fail(String),
28	    Skip(String),
29	}
30	
31	// ── Case and Section ───────────────────────────────────────────
32	
33	/// A named test case with a function that receives its isolated temp directory.
34	/// The `name` field holds the raw stringified function name (from the `case!` macro).
35	pub struct rbtdre_Case {
36	    pub name: &'static str,
37	    pub func: fn(&Path) -> rbtdre_Verdict,
38	}
39	
40	/// A named group of test cases, printed as a section header during execution.
41	pub struct rbtdre_Section {
42	    pub name: &'static str,
43	    pub cases: &'static [rbtdre_Case],
44	}
45	
46	/// Case registration macro. Derives case name from function name via `stringify!`.
47	/// Compiler enforces uniqueness — duplicate function names won't compile.
48	#[macro_export]
49	macro_rules! case {
50	    ($func:path) => {
51	        $crate::rbtdre_engine::rbtdre_Case {
52	            name: stringify!($func),
53	            func: $func,
54	        }
55	    };
56	}
57	
58	// ── Colors ─────────────────────────────────────────────────────
59	
60	/// Terminal color codes, empty strings when color is disabled.
61	pub struct rbtdre_Colors {
62	    pub green: &'static str,
63	    pub red: &'static str,
64	    pub yellow: &'static str,
65	    pub white: &'static str,
66	    pub reset: &'static str,
67	}
68	
69	/// Detect terminal color support from TERM environment variable.
70	pub fn rbtdre_detect_colors() -> rbtdre_Colors {
71	    match std::env::var("TERM") {
72	        Ok(term) if !term.is_empty() && term != "dumb" => rbtdre_Colors {
73	            green: "\x1b[1;32m",
74	            red: "\x1b[1;31m",
75	            yellow: "\x1b[1;33m",
76	            white: "\x1b[1;37m",
77	            reset: "\x1b[0m",
78	        },
79	        _ => rbtdre_Colors {
80	            green: "",
81	            red: "",
82	            yellow: "",
83	            white: "",
84	            reset: "",
85	        },
86	    }
87	}
88	
89	// ── Trace ──────────────────────────────────────────────────────
90	
91	/// Write verdict and detail to a trace file in the case temp directory.
92	fn rbtdre_write_trace(case_dir: &Path, display_name: &str, verdict: &rbtdre_Verdict) {
93	    let content = match verdict {
94	        rbtdre_Verdict::Pass => format!("PASSED: {}\n", display_name),
95	        rbtdre_Verdict::Fail(detail) => format!("FAILED: {}\n\n{}\n", display_name, detail),
96	        rbtdre_Verdict::Skip(reason) => {
97	            format!("SKIPPED: {}\n\nReason: {}\n", display_name, reason)
98	        }
99	    };
100	    let _ = std::fs::write(case_dir.join("trace.txt"), content);
101	}
102	
103	// ── Dispatch ───────────────────────────────────────────────────
104	
105	/// Aggregate results from running sections.
106	pub struct rbtdre_RunResult {
107	    pub passed: usize,
108	    pub failed: usize,
109	    pub skipped: usize,
110	    pub temp_dir: PathBuf,
111	}
112	
113	/// Run all sections sequentially, dispatching each case with per-case temp dir isolation.
114	pub fn rbtdre_run_sections(
115	    sections: &[rbtdre_Section],
116	    colors: &rbtdre_Colors,
117	    fail_fast: bool,
118	    root_temp: &Path,
119	) -> Result<rbtdre_RunResult, String> {
120	    let mut passed = 0usize;
121	    let mut failed = 0usize;
122	    let mut skipped = 0usize;
123	
124	    'outer: for section in sections {
125	        eprintln!(
126	            "\n{}--- {} ---{}",
127	            colors.white, section.name, colors.reset
128	        );
129	
130	        for case in section.cases {
131	            let case_dir = root_temp.join(case.name);
132	            std::fs::create_dir_all(&case_dir).map_err(|e| {
133	                format!("rbtd: failed to create case dir '{}': {}", case.name, e)
134	            })?;
135	
136	            let verdict = (case.func)(&case_dir);
137	            rbtdre_write_trace(&case_dir, case.name, &verdict);
138	
139	            match &verdict {
140	                rbtdre_Verdict::Pass => {
141	                    eprintln!("{}PASSED:{} {}", colors.green, colors.reset, case.name);
142	                    passed += 1;
143	                }
144	                rbtdre_Verdict::Fail(_) => {
145	                    eprintln!("{}FAILED:{} {}", colors.red, colors.reset, case.name);
146	                    failed += 1;
147	                    if fail_fast {
148	                        break 'outer;
149	                    }
150	                }
151	                rbtdre_Verdict::Skip(_) => {
152	                    eprintln!(
153	                        "{}SKIPPED:{} {}",
154	                        colors.yellow, colors.reset, case.name
155	                    );
156	                    skipped += 1;
157	                }
158	            }
159	        }
160	    }
161	
162	    Ok(rbtdre_RunResult {
163	        passed,
164	        failed,
165	        skipped,
166	        temp_dir: root_temp.to_path_buf(),
167	    })
168	}
169	
170	/// Print colored summary line and trace directory location.
171	pub fn rbtdre_print_summary(result: &rbtdre_RunResult, colors: &rbtdre_Colors) {
172	    let total = result.passed + result.failed + result.skipped;
173	    let (color, end_color) = if result.failed > 0 {
174	        (colors.red, colors.reset)
175	    } else {
176	        (colors.green, colors.reset)
177	    };
178	
179	    eprintln!(
180	        "\n{}{} passed, {} failed, {} skipped ({} total){}",
181	        color, result.passed, result.failed, result.skipped, total, end_color,
182	    );
183	    eprintln!("Trace dir: {}", result.temp_dir.display());
184	}
185	
186	// ── Single-case operations ───────────────────────────────────
187	
188	/// Find a case by name within sections.
189	pub fn rbtdre_find_case<'a>(
190	    sections: &'a [rbtdre_Section],
191	    target: &str,
192	) -> Option<&'a rbtdre_Case> {
193	    for section in sections {
194	        for case in section.cases {
195	            if case.name == target {
196	                return Some(case);
197	            }
198	        }
199	    }
200	    None
201	}
202	
203	/// List all cases grouped by section.
204	pub fn rbtdre_list_cases(sections: &[rbtdre_Section]) {
205	    for section in sections {
206	        eprintln!("\n--- {} ---", section.name);
207	        for case in section.cases {
208	            eprintln!("  {}", case.name);
209	        }
210	    }
211	}
212	
213	/// Run a single case without charge/quench lifecycle.
214	pub fn rbtdre_run_single_case(
215	    case: &rbtdre_Case,
216	    colors: &rbtdre_Colors,
217	    root_temp: &Path,
218	) -> Result<rbtdre_RunResult, String> {
219	    let case_dir = root_temp.join(case.name);
220	    std::fs::create_dir_all(&case_dir)
221	        .map_err(|e| format!("rbtd: failed to create case dir '{}': {}", case.name, e))?;
222	
223	    let verdict = (case.func)(&case_dir);
224	    rbtdre_write_trace(&case_dir, case.name, &verdict);
225	
226	    let (passed, failed, skipped) = match &verdict {
227	        rbtdre_Verdict::Pass => {
228	            eprintln!("{}PASSED:{} {}", colors.green, colors.reset, case.name);
229	            (1, 0, 0)
230	        }
231	        rbtdre_Verdict::Fail(_) => {
232	            eprintln!("{}FAILED:{} {}", colors.red, colors.reset, case.name);
233	            (0, 1, 0)
234	        }
235	        rbtdre_Verdict::Skip(_) => {
236	            eprintln!("{}SKIPPED:{} {}", colors.yellow, colors.reset, case.name);
237	            (0, 0, 1)
238	        }
239	    };
240	
241	    Ok(rbtdre_RunResult {
242	        passed,
243	        failed,
244	        skipped,
245	        temp_dir: root_temp.to_path_buf(),
246	    })
247	}
